#include <bits/stdc++.h>
using namespace std;
int main(){
    int ans=0,n,d[250004],w[250004];
    stack<int> s;
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d%d",&d[i],&w[i]);
        while(s.size() && w[s.top()]>w[i])
            s.pop(),ans++;
        if(s.empty() || w[s.top()]!=w[i])
            s.push(i);
    }
    ans+=s.size();
    printf("%d",ans);
    return 0;
}
